// Story 7.2 AC1: bail cleanly on non-200 (logs but does not crash n8n).
// AC2: parse RSS items, compute sha256(canonical_url), drop items whose hash
//      is already in workflow static data under key `upwork.seen_urls`.
// FR11: this node never logs in, never sends a session cookie, and never
//       touches a browser-automation node. Public RSS only.

const statusCode = $json.statusCode || ($json.headers ? $json.headers.statusCode : 200);
if (statusCode && statusCode >= 400) {
  console.log('upwork-rss: non-200 response, exiting clean. status=' + statusCode);
  return [];
}

const body = typeof $json.body === 'string' ? $json.body : ($json.data || '');
if (!body) {
  console.log('upwork-rss: empty body, exiting clean.');
  return [];
}

// Minimal RSS <item> extractor — no external deps so this stays hosting-agnostic.
const itemRe = /<item[\s\S]*?<\/item>/g;
const rawItems = body.match(itemRe) || [];

function pick(xml, tag) {
  const m = xml.match(new RegExp('<' + tag + '(?:[^>]*)>([\\s\\S]*?)<\\/' + tag + '>'));
  if (!m) return '';
  let v = m[1];
  // strip CDATA wrapper if present
  v = v.replace(/^\s*<!\[CDATA\[([\s\S]*?)\]\]>\s*$/, '$1');
  return v.trim();
}

function stripHtml(s) {
  return s.replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/\s+/g, ' ').trim();
}

function canonicalUrl(u) {
  if (!u) return '';
  // Drop tracking query / fragment; keep scheme + host + path.
  try {
    const parsed = new URL(u);
    return parsed.origin + parsed.pathname.replace(/\/$/, '');
  } catch (e) {
    return u.split('?')[0].split('#')[0].replace(/\/$/, '');
  }
}

function sha256Hex(s) {
  const crypto = require('crypto');
  return crypto.createHash('sha256').update(s, 'utf8').digest('hex');
}

const staticData = getWorkflowStaticData('global');
if (!staticData['upwork.seen_urls'] || typeof staticData['upwork.seen_urls'] !== 'object') {
  staticData['upwork.seen_urls'] = {};
}
const seen = staticData['upwork.seen_urls'];

const out = [];
const nowIso = new Date().toISOString();
for (const raw of rawItems) {
  const link = canonicalUrl(pick(raw, 'link'));
  if (!link) continue;
  const hash = sha256Hex(link);
  if (seen[hash]) continue;
  const description = pick(raw, 'description');
  const title = pick(raw, 'title');
  const jdText = stripHtml((title ? title + '\n\n' : '') + description);
  if (!jdText) continue;
  out.push({
    json: {
      source: 'upwork',
      jd_text: jdText,
      url: link,
      discovered_at: nowIso,
      _url_hash: hash
    }
  });
}
return out;

// Story 7.2 AC3: record the hash ONLY on 2xx — non-2xx leaves the hash
// unrecorded so the next cron tick retries this item. The hash comes from
// the upstream Dedup node via n8n's per-item node reference, since the
// HTTP Request response body replaces $json for this item.

const status = $json.statusCode || ($json.headers && $json.headers.statusCode) || 0;
const upstream = $node['Dedup + build canonical body'] && $node['Dedup + build canonical body'].json;
const sourceHash = (upstream && upstream._url_hash) || $json._url_hash || '';

const staticData = getWorkflowStaticData('global');
if (!staticData['upwork.seen_urls'] || typeof staticData['upwork.seen_urls'] !== 'object') {
  staticData['upwork.seen_urls'] = {};
}

if (status >= 200 && status < 300 && sourceHash) {
  staticData['upwork.seen_urls'][sourceHash] = new Date().toISOString();
  return [{ json: { recorded: true, status: status, hash: sourceHash } }];
}
console.log('upwork-rss: ingest non-2xx, not recording hash. status=' + status);
return [{ json: { recorded: false, status: status } }];
